/**
 * Pure validation functions for order operations.
 *
 * These validators contain no side effects and no database calls.
 * They can be reused across services that need order validation logic.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Validate that a create-order input has at least one item.
 * Throws if the items array is empty.
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Check whether a status transition is allowed.
 */
export function isValidOrderStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing if it is not allowed.
 */
export function validateOrderStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidOrderStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Pure validation functions for user operations.
 *
 * These validators contain no side effects and no database calls.
 * They can be reused across services that need user validation logic.
 */

import type { User, UpdateUserInput } from '../models/user.js';

/**
 * Validate that an email is not already taken by another user.
 * Throws if existingUser is defined (i.e., a user with that email already exists).
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email change does not conflict with an existing user.
 * Throws if the email is changing and is already in use.
 */
export function validateEmailChangeAllowed(
  newEmail: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`Email ${newEmail} is already in use`);
  }
}

/**
 * Detect which fields changed between an existing user and an update input.
 * Returns an array of field names that differ.
 */
export function detectUserChanges(
  existing: User,
  input: UpdateUserInput,
): string[] {
  const changes: string[] = [];
  if (input.name && input.name !== existing.name) changes.push('name');
  if (input.email && input.email !== existing.email) changes.push('email');
  if (input.role && input.role !== existing.role) changes.push('role');
  return changes;
}

