import { describe, it, expect } from 'vitest';
import {
  validateCreateOrderInput,
  isValidOrderStatusTransition,
  validateOrderStatusTransition,
} from '../../src/validators/order.validator.js';
import type { OrderStatus } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('validateCreateOrderInput', () => {
    it('should pass for input with items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });
  });

  describe('isValidOrderStatusTransition', () => {
    const validTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'confirmed'],
      ['pending', 'cancelled'],
      ['confirmed', 'shipped'],
      ['confirmed', 'cancelled'],
      ['shipped', 'delivered'],
    ];

    it.each(validTransitions)(
      'should allow %s -> %s',
      (from, to) => {
        expect(isValidOrderStatusTransition(from, to)).toBe(true);
      },
    );

    const invalidTransitions: [OrderStatus, OrderStatus][] = [
      ['pending', 'shipped'],
      ['pending', 'delivered'],
      ['confirmed', 'pending'],
      ['confirmed', 'delivered'],
      ['shipped', 'pending'],
      ['shipped', 'confirmed'],
      ['shipped', 'cancelled'],
      ['delivered', 'pending'],
      ['delivered', 'confirmed'],
      ['delivered', 'shipped'],
      ['delivered', 'cancelled'],
      ['cancelled', 'pending'],
      ['cancelled', 'confirmed'],
      ['cancelled', 'shipped'],
      ['cancelled', 'delivered'],
    ];

    it.each(invalidTransitions)(
      'should reject %s -> %s',
      (from, to) => {
        expect(isValidOrderStatusTransition(from, to)).toBe(false);
      },
    );
  });

  describe('validateOrderStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateOrderStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
      expect(() => validateOrderStatusTransition('delivered', 'shipped')).toThrow(
        'Invalid status transition: delivered -> shipped',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailNotTaken,
  validateEmailChangeAllowed,
  detectUserChanges,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('user.validator', () => {
  describe('validateEmailNotTaken', () => {
    it('should pass when no existing user has the email', () => {
      expect(() => validateEmailNotTaken('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already taken', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailNotTaken('taken@example.com', existing)).toThrow(
        'User with email taken@example.com already exists',
      );
    });
  });

  describe('validateEmailChangeAllowed', () => {
    it('should pass when no user has the new email', () => {
      expect(() => validateEmailChangeAllowed('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when the new email is already in use', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailChangeAllowed('taken@example.com', existing)).toThrow(
        'Email taken@example.com is already in use',
      );
    });
  });

  describe('detectUserChanges', () => {
    it('should detect name change', () => {
      const existing = makeUser({ name: 'Alice' });
      const changes = detectUserChanges(existing, { name: 'Bob' });
      expect(changes).toEqual(['name']);
    });

    it('should detect email change', () => {
      const existing = makeUser({ email: 'alice@example.com' });
      const changes = detectUserChanges(existing, { email: 'bob@example.com' });
      expect(changes).toEqual(['email']);
    });

    it('should detect role change', () => {
      const existing = makeUser({ role: 'member' });
      const changes = detectUserChanges(existing, { role: 'admin' });
      expect(changes).toEqual(['role']);
    });

    it('should detect multiple changes', () => {
      const existing = makeUser({ name: 'Alice', email: 'alice@example.com', role: 'member' });
      const changes = detectUserChanges(existing, {
        name: 'Bob',
        email: 'bob@example.com',
        role: 'admin',
      });
      expect(changes).toEqual(['name', 'email', 'role']);
    });

    it('should return empty array when nothing changed', () => {
      const existing = makeUser({ name: 'Alice', email: 'alice@example.com' });
      const changes = detectUserChanges(existing, {});
      expect(changes).toEqual([]);
    });

    it('should return empty array when values are the same', () => {
      const existing = makeUser({ name: 'Alice', email: 'alice@example.com' });
      const changes = detectUserChanges(existing, { name: 'Alice', email: 'alice@example.com' });
      expect(changes).toEqual([]);
    });
  });
});
